﻿/**********************************************/
/*  AiR RUI common Standard　style   	      */
/*  2020/09/11　　                             */
/**********************************************/
* {
margin: 0;
padding: 0;
font-size: small;
font-weight: normal;
line-height: auto;
}
body {
color: #000000;
background-color: #fefefe;
}
table {
border-collapse: collapse;
border-spacing: 0px;
}
a:link,
a:visited {
color: #ffffff;
text-decoration: none;
}
a:hover {
color: #efefef;
text-decoration: none;
}
a:active {
color: #efefef;
text-decoration: none;
}
hr {
display: none;
}
legend {
display: none;
}
fieldset {
border: none;
}
img {
vertical-align: middle;
border: none;
}
select {
vertical-align: middle;
margin: 3px 0;
padding: 0;
font-weight: normal;
line-height: auto;
font-size: 1em;
min-width: 60px;
/ min-width: auto;
}
select option {
padding: 0 1ex;
font-size: 1em;
}
input {
vertical-align: middle;
padding: 1px 6px 1px 2px;
font-weight: normal;
font-size: 1em;
}

textarea {
vertical-align: middle;
padding: 2px;
}

/*-- common style --*/
.Supplement {
display: none;
}

.Wrapper {
background: transparent;
zoom: 1;
}
.Wrapper:after {/* firefox */
content: "";
display: block;
clear: both;
}

.TextReadOnly {
color: #000000;
background: #e7e7e7;
}

/*--.Buttons--*/

.TransitionOperation input.ButtonEnable,
.TransitionOperation input.ButtonEnable:hover,
.TransitionOperation input.ButtonEnable:active,
.TransitionOperation input.ButtonDisable {
min-width: 7em;
/ min-width: auto;
}
.ConfirmOperation input.ButtonEnable,
.ConfirmOperation input.ButtonDisable{
min-width: 7em;
/ min-width: auto;
}
.ContentOperation input.ButtonEnable,
.ContentOperation input.ButtonDisable{
min-width: 7em;
/ min-width: auto;
}
input.ButtonEnable {
font-weight: normal;
width: auto;
padding: 4px 8px;
margin: 2px 0;
border: 1px solid #cccccc;
background: #eeeeee;
line-height:  auto;
}
input.ButtonEnable:hover {
border: 1px solid #cccccc;
background: #f8f4c9;
}
input.ButtonEnable:active {
border: 1px solid #cccccc;
background: #efe695;
}
input.ButtonDisable {
font-weight: normal;
width: auto;
padding: 4px 8px;
margin: 2px 0;
border: 1px solid #cccccc;
background: #dedede;
color: #a0a0a0;
line-height: auto;
}

.ItemListComponent input.ButtonEnable,
.ItemListComponent input.ButtonEnable:hover,
.ItemListComponent input.ButtonEnable:active,
.ItemListComponent input.ButtonDisable {
min-width: 4em;
/ min-width: auto;
}
input.ButtonEnable:disabled,
.ItemListComponent input.ButtonEnable:disabled {
border: 1px solid #cccccc;
background: #eeeeee;
}
a.Button {
display: block;
float: left;
padding: 3px 5px;
margin: 2px 4px 2px 0;
line-height: 1.2em !important;
white-space: nowrap;
text-decoration: none !important;
border: 1px solid #cccccc;
background: #eeeeee;
}
a.Button:link ,
a.Button:visited {
border: 1px solid #cccccc;
background: #eeeeee;
text-decoration: none;
}
a.Button:hover {
border: 1px solid #cccccc;
background: #f8f4c9;
text-decoration: none;
}
a.Button:active ,
a.Button:focus {
border: 1px solid #cccccc;
background: #efe695;
text-decoration: none;
}
button.ButtonEnable {
width: auto;
padding: 2px 4px;
margin: 2px 0;
border: 1px solid #cccccc;
background: #eeeeee;
color: #232323;
}
button.ButtonDisable {
width: auto;
padding: 2px 4px;
margin: 2px 0;
border: 1px solid #cccccc;
background: #dedede;
color: #a0a0a0;
}
button img {
margin: 0;
vertical-align: middle;
border: none;
}
button span {
vertical-align: middle;
line-height: 17px;
}

/*-- basic layout ------------------------------*/
/*--#container--*/
#container {
margin: 0 auto;
width: 100%;
min-width: 760px;
text-align: left;
}
/*--#ruiCommons--*/
#ruiCommons {
clear: both;
color: #ffffff;
background: #0f0f0f;
padding: 4px 0;
zoom: 1;
}
#ruiCommons:after {/* firefox */
content: "";
display: block;
clear: both;
}
/*-- #applications --*/
#applications {
position: relative;
zoom: 1;
}
#applications:after {/* firefox */
content: "";
display: block;
clear: both;
}
/*-- field style ------------------------------*/

/*--#commonBranding--*/
#commonBranding {
float: left;
padding: 0 11px;
}
#commonBranding a:link ,
#commonBranding a:visited {
text-decoration: none;
}
#commonBranding a:hover ,
#commonBranding a:active ,
#commonBranding a:focus {
text-decoration: none;
}
#commonBranding #deviceLogo {
display: inline;
}
#commonBranding #deviceLogo img {
display: none;
}
#commonBranding #deviceLogo > img {
display: none;
}
#commonBranding #deviceLogo span{
font-weight: bold;
}
#commonBranding #deviceLogo a:link ,
#commonBranding #deviceLogo a:visited {
color: #d2d2d2;
text-decoration: none;
}
#commonBranding #deviceLogo a:hover {
color: #ffffff;
text-decoration: none;
}
#commonBranding #deviceLogo a:active,
#commonBranding #deviceLogo a:focus {
color: #adadad;
text-decoration: none;
}
#commonBranding #deviceType {
margin: 0px 0px 0px 50px ;
display: inline;
padding: 0 6px;
color: #dfdfdf;
}
#commonBranding #deviceType span{
font-weight: bold;
}

/*--#commonTools--*/
#commonTools {
float: right;
text-align: right;
margin-right: 6px;
}
#commonTools * {
font-weight: bold;
line-height: 1.2em;
}
#commonTools fieldset{
float: left;
margin: 0px 6px 0 6px;
color: #d2d2d2;
white-space: nowrap;
}
#commonTools p {
display: inline;
}
#loginUserData .Supplement {
display: inline;
margin: 0 2px 0 12px;
}
#userName {
	margin: 0 6px 0 6px;
}
#commonTools p span ,
#commonTools p a {
white-space: nowrap;
z-index: 2;
}
#commonTools a:link ,
#commonTools a:visited {
color: #d2d2d2;
text-decoration: none;
border-bottom: 1px dotted #d2d2d2;
}
#commonTools a:hover {
color:#ffffff;
text-decoration: none;
border-bottom: 1px dotted #ffffff;
}
#commonTools a:active ,
#commonTools a:focus {
color:#adadad;
text-decoration: none;
border-bottom: 1px solid #adadad;
}
/*-- #applicationBranding --*/
#applicationBranding {
background: #232323;
color:#ffffff;
clear:both;
zoom: 1;
}
#applicationBranding:after {/* firefox */
content: "";
display: block;
clear: both;
}
#applicationLogo {
display: block;
float: left;
width: auto;
height: 32px;
line-height: 32px;
padding: 2px 0 4px 10px;
}
#applicationLogo img {
display: inline;
margin-right: 8px;
vertical-align: -10px;
}
#applicationLogo .BrandingName {
sdisplay: inline;
line-height: 100%;
font-size: 120%;
font-weight: bold;
}
#appTools {
float: right;
display: block;
white-space: nowrap;
text-align: right;
line-height: 32px;
padding: 0 8px;
}
#appTools fieldset{
display: inline;
margin: 0px 5px;
vertical-align: middle;
line-height: 32px;
}
#appTools span {
line-height: 32px;
}
#appTools a {
margin: 0 5px 0 2px;
line-height: 14px;
}
#appTools a:link ,
#appTools a:visited {
color: #d2d2d2;
text-decoration: none;
border-bottom: 1px dotted #d2d2d2;
}
#appTools a:hover {
color: #ffffff;
text-decoration: none;
border-bottom: 1px dotted #ffffff;
}
#appTools a:active ,
#appTools a:focus {
color: #adadad;
text-decoration: none;
border-bottom: 1px solid #adadad;
}
#appTools select {
line-height: 14px;
margin: 6px 0;
}
#appTools a.ImgButton {
margin: 0;
line-height: 14px;
border: none !important;
}
/*-- #applicationContents --*/

#applicationContents {
position: relative;
background: #ffffff url("../media/contents_bg_l.png") left top repeat-y;
zoom: 1;
}
#applicationContents:after {/* firefox */
content: "";
display: block;
clear: both;
}

#applicationContents .Wrapper:after {
content: "";
display: block;
clear: both;
}
#applicationContents .Wrapper {
display: inline-block;
width: 100%;
} 

/* for IE6 */
#contentsWrapper {
width: auto;
padding: 0 0 0 250px;
zoom: 1;
}
#contents {
padding: 10px 10px 10px 28px;
}
#navigationWrapper {
position: absolute;
top: 0;
left: 0;
width: 250px;
padding: 0;
zoom: 1;
line-height: auto;
}
/* for no IE6 overwrite */
* > #contentsWrapper {
width: 100%;
padding: 0;
float: right;
margin: 0 0 0 -250px;
zoom: 1;
}
* > #contents {
margin: 0 0 0 250px;
padding: 10px 28px 10px 28px;
}
* > #navigationWrapper {
position: static;
top: auto;
left: auto;
float: right;
width: 250px;
padding: 0;
zoom: 1;
}

/*--#navigation --*/
#navigation {
width: 249px;
margin-left: 1px;
}
#navigation h2 {
display: none;
}
#navigation h3 {
display: none;
}
#navigation ul { 
line-height: 20px;
}
#navigation ul li {
list-style: none;
display: block;
margin:0;
}
#navigation ul li span.GroupTitle {
display: block;
margin: 0px;
padding: 2px 11px 0 11px;
font-size: 90%;
font-weight: bold;
border-bottom: 1px solid #dedede;
}
#navigation ul li a {
display: block;
padding: 8px 1.5em;
margin: 0;
}
#navigation ul li a:link ,
#navigation ul li a:visited { 
color: #232323;
border-right: 1px solid #dedede;
}
#navigation ul li a:hover,
#navigation ul li a:focus {
color: #232323;
background:#f8f4c9;
border-right: 1px solid #dedede;
}
#navigation ul li a:active {
color: #232323;
background: #efe695;
border-right: 1px solid #dedede;
}
#navigation ul li.Selected a {
background:#ffffff;
color: #232323;
border-right: 1px solid #dedede;
}
#navigation ul li.Selected a:link ,
#navigation ul li.Selected a:visited {
background:#ffffff;
color: #232323;
border-right: 1px solid #dedede;
}
.MainItem .Sub{
border-bottom: 1px solid #cccccc;
}
/*-- #applicationInfo --*/
#applicationInfo {
clear: both;
text-align: right;
padding: 6px 0 6px 0;
width: 100%;
height: 1.4em;
background:#0f0f0f;
color: #ffffff;
position:relative;
}
span.TechInfo {
float: left;
}
#changeView {
padding: 2px 12px;
font-size: 90%;
float: left;
line-height: 1em;
font-style: normal;
}
#changeView a:link ,
#changeView a:visited {
color: #d2d2d2;
border-bottom: 1px dotted #d2d2d2;
text-decoration: none;
}
#changeView a:hover {
color: #ffffff;
border-bottom: 1px dotted #ffffff;
text-decoration: none;
}
#changeView a:active,
#changeViewo a:focus {
color: #adadad;
border-bottom: 1px solid #adadad;
text-decoration: none;
}
address.SiteInforLegal {
padding: 2px 12px;
font-size: 90%;
float: right;
line-height: 1em;
font-style: normal;
}
/*--.GotoTop--*/
#tmpFooter {
	clear: both;
}
.GotoTop {
margin: 1ex 0;
padding: 2px 0;
border-top: 1px solid #d6d6d6;
}
/*--navTopicPath--*/
#navTopicPath {
margin: 0 0 6px 0;
padding: 1px 0 0 0;
background: #ffffff;
font-size: small;
color: #666666;
zoom: 1;
}
#navTopicPath:after {/* firefox */
content: "";
display: block;
clear: both;
}
#navTopicPath h4 {
display: none;
}
#navTopicPath a {
text-decoration: none;
font-size: small;
}
#navTopicPath a:link ,
#navTopicPath a:visited {
color: #666666;
border-bottom: none;
}
#navTopicPath a:hover {
color: #0041D7;
padding-bottom: 1px;
border-bottom: 1px dotted #0041D7;
}
#navTopicPath a:active,
#navTopicPath a:focus {
color: #002f8c;
border-bottom: 1px solid #002f8c;
}
#navTopicPath span {
text-decoration: none;
font-size: small;
color: #666666;
}
/*--#contentHeading--*/
#contentHeading {
zoom: 1;
clear: both;
margin-bottom: 6px;
border-bottom: 1px solid #CCCCCC;
}
#contentHeading:after {/* firefox */
content: "";
display: block;
clear: both;
}
#contentHeading h2.PageName {
font-size: 150%;
font-weight: bold;
float: left;
padding: 2px 12px 0px 0px;
}
#contentHeading h2.PageName img {
margin: 0 4px;
}
/*--#contentHeadingTools--*/
#contentHeadingTools {
float: right;
width: auto;
margin: auto;
}
#tmpReload {
	float: left;
	margin: -3px 0px 0px 6px;
	padding: 7px 0px 4px 0px;
	width: 24px;
	line-height: 24px;
}

#tmpUpdate {
	float: left;
	padding-top: 5px;
	font-size: 90%;
	white-space: nowrap;
	line-height:22px;
}
/*--#contentInformation--*/
#contentInformation {
margin: 0px;
display: block;
padding: 6px 5px;
max-width: 70%;
/max-width: 100%;
line-height: 1.3em;
float:left;
/float: clear;
zoom: 1;
}
#contentInformation:after {/* firefox */
content: "";
display: block;
clear: both;
}
#contentInformation ul{
margin-top: 8px;
margin-left: 1.5em;
color: #333333;
}
#contentInformation li{
line-height: 1.2em;
}
/*--.ContentOperation--*/
.ContentOperation fieldset ,
.ConfirmOperation fieldset {
margin: 0;
padding: 0;
border-top: none;
white-space: nowrap;
text-align: right;
}
.ContentOperation legend ,
.ConfirmOperation legend {
display: none;
}

/*--#availableMemory--*/
#availableMemory {
display: block;
text-align: right;
margin: 8px 0;
}
#availableMemory span.Property {
font-weight: bold;
}
#availableMemory span.Value {
font-weight: bold;
}
#availableMemory img {
	margin: 0;
}
/*-- ContentModule --*/
.ContentModule {
margin-bottom: 12px;
clear: both;
}
.ContentModule .ModuleHeading h4 {
margin: 6px 0;
}
/*--.ModuleHeading--*/
.ModuleHeading { 
display: block;
zoom: 1;
}
.ModuleHeading:after {/* firefox */
content: "";
display: block;
clear: both;
}
.ModuleHeading h4 {
font-size: 100%;
font-weight: bold;
color: #232323;
background: #dedede;
padding: 4px 1px 2px 6px;
clear: both;
}
.ModuleHeadingSub { 
display: block;
margin: 0;
background: #cccccc url("") repeat-x ;
padding: 2px 4px;
zoom: 1;
}
.ModuleHeadingSub:after {/* firefox */
content: "";
display: block;
clear: both;
}
.ModuleHeadingSub h4 {
font-size: 100%;
font-weight: bold;
color: #3e4555;
}
/*--.ModuleElement--*/
.ContentModule .ModuleElement {
margin: 0 1em;
zoom: 1;
clear: both;
}
.ModuleElement:after {/* firefox */
content: "";
display: block;
clear: both;
}
.ModuleElement h5 {
padding: 6px 0px 0px 0px;
font-size: 100%;
color: #232323;
border-bottom: 1px solid #999999;
font-weight: bold;
height: auto;
}
.ModuleElement table {
margin: 0;
width: 100%;
}
.ModuleElement table thead tr {
color: #000000;
}
.ModuleElement table thead th {
white-space: nowrap;
padding: 3px 30px 3px 6px;
text-align: left;
white-space: nowrap;
color: #232323;
}
.ModuleElement table tbody th {
padding: 4px 6px;
white-space: nowrap;
text-align: left;
color: #000000;
}
.ModuleElement table tbody td {
padding: 2px 7px;
}
.ModuleElement table td input.Button {
margin-right: 1px;
padding: 1px;
}
.ModuleElement input {
margin-right: 1px;
}
.ModuleElement a:link ,
.ModuleElement a:visited {
color: #002f8c;
text-decoration: none;
border-bottom: 1px dotted #002f8c;
}
.ModuleElement a:hover {
color: #0041D7;
text-decoration: none;
border-bottom: 1px dotted #0041D7;
}
.ModuleElement a:active ,
.ModuleElement a:focus {
text-decoration: none;
border-bottom: 1px solid #002f8c;
}
.ModuleElement a.Button {
padding: 6px 10px;
}
.ModuleElement a.Button:link ,
.ModuleElement a.Button:visited {
color: #000000;
border: 1px solid #cccccc;
}
.ModuleElement a.Button:hover {
color: #000000;
border: 1px solid #cccccc;
}
.ModuleElement a.Button:active ,
.ModuleElement a.Button:focus {
color: #000000;
border: 1px solid #cccccc;
}

/*-- ContentModule .PropertyListComponent --*/
.ContentModule .ModuleElement table.PropertyListComponent {
width: 100%;
border: none;
line-height: 20px;
padding:5px 1em;
}
.ContentModule .ModuleElement table.PropertyListComponent thead {
display: none;
border: none;
}
.ContentModule .ModuleElement table.PropertyListComponent tbody {
border: none;
}
.ContentModule .ModuleElement table.PropertyListComponent th {
width: 35%;
text-align: left;
vertical-align: top;
color: #000000;
padding: 2px 1em;
border-top: 0px;
border-bottom: 1px solid #ffffff;
border-left: 0px;
}
.ContentModule .ModuleElement table.PropertyListComponent td {
text-align: left;
vertical-align: top;
color: #000000;
padding: 3px 0px;
border: none;
}
/*-- ContentModule .ItemListComponent --*/
.ContentModule .ModuleElement .ItemListComponent table {
width: 100%;

}

.ContentModule .ModuleElement .ItemListComponent table thead th {
padding: 3px 15px 3px 5px;
text-align: left;
white-space: nowrap;
color: #000000;
background: #eeeeee;
border-right: 1px solid #ffffff;
border-bottom:1px solid #ffffff;
}

.ContentModule .ModuleElement .ItemListComponent table tbody th ,
.ContentModule .ModuleElement .ItemListComponent table tbody td {
line-height: 20px;
text-align: left;
color: #000000;
padding: 2px 7px;
border-width: 0 0 1px 0;
border-bottom: 1px dotted #dddddd;
}
.ContentModule .ModuleElement .ItemListComponent table tbody td a {
display: block;
float: left;
line-height: 28px;
padding-right: 5px;
}
.ContentModule .ModuleElement .ItemListComponent table tbody td.CountLimit{
color: #ee0000;
}
/*-- ContentModule .ErrorListComponent --*/
.ContentModule .ModuleElement table.ErrorListComponent thead {
display: none;
border: none;
}
.ContentModule .ModuleElement table.ErrorListComponent th ,
.ContentModule .ModuleElement table.ErrorListComponent td{
padding-top: 8px;
}
.ContentModule .ModuleElement table.ErrorListComponent th {
width: 40px;
}
#noErrorInformation, 
#errorInformation{
margin: 12px 6px;
}

/*--table tr OddColumn / EvenColumn --*/
tr.OddColumn th ,
tr.OddColumn td {
border-bottom:solid 1px #e8e8e8;
}
tr.EvenColumn th ,
tr.EvenColumn td {
background:#f5f6f8;
border-bottom:solid 1px #e8e8e8;
}
tr.OddColumn td.NewInput {
background-color: #eeeeee;
border-right: 1px solid #ffffff;
}
tr.EvenColumn td.NewInput {
background-color: #e4e8ee;
border-right: 1px solid #ffffff;
}

/* col */
colgroup{
border: 0px;
}
col.SelectColumn{
width: 2em;
white-space: nowrap;
}
col.TypeColumn{
width: auto;
white-space: nowrap;
}
.ContentModule .ModuleElement .ItemListComponent table thead.SortOperation tr th {
	padding: 0px;
	text-align: left;
	vertical-align: middle;
	background: #eeeeee;
	border-right: 1px solid #ffffff;
	text-indent: 6px;
}


.ItemListComponent table thead.SortOperation tr th a {
	display: block;
	padding: 5px 20px 5px 3px;
	height: 1.1em;
	line-height: 1.1em;
	background: #eeeeee;
	color: #000000;
	border: none;
	background-position: right;
	background-repeat: no-repeat;
	white-space: nowrap;
}
.ItemListComponent table thead.SortOperation tr th a:link,
.ItemListComponent table thead.SortOperation tr a:visited {
	text-decoration: none;
}
.ItemListComponent table thead.SortOperation tr th a:hover {
	text-decoration: none;
	background: #f8f4c9;
	color: #000000;
}
.ItemListComponent table thead.SortOperation tr th a:active {
	text-decoration: none;
	background: #efe695;
	color: #000000;
}

.ItemListComponent table thead.SortOperation tr th.Sort_up a {
	background-image: url("./surface/list_sort_up.gif");

}

.ItemListComponent table thead.SortOperation tr th.Sort_down a {
	background-image: url("./surface/list_sort_down.gif");
}
.ItemOperation a {
font-size: 90%;
}
.ItemOperation button {
font-size: 90%;
}
/*---.ContentModuleEditable--*/
.ContentModuleEditable {
margin: 6px 0 12px 0;
background: #eeeeee;
zoom: 1;
clear: both;
}
.ContentModuleEditable h5{
margin: 0 1em;
}
.ContentModuleEditable table {
width: 100%;
padding:5px 1em;	
}

.ContentModuleEditable table th h5{
margin: 0 6px 0 0;
}
.ContentModuleEditable .ModuleElement table {
	margin-top: 3px;
	border: none;
}
.ContentModuleEditable .ModuleElement table th ,
.ContentModuleEditable .ModuleElement table td {
border-width:  0;
}
.ContentModuleEditable .ModuleElement table.PropertyListComponent {}
.ContentModuleEditable .ModuleElement table.PropertyListComponent thead {
display: none;
}

.ContentModuleEditable .ModuleElement table.PropertyListComponent , /* FireFox *//* IE is [rules="groups"] property */
.ContentModuleEditable .ModuleElement table.PropertyListComponent tbody {
border:none;
}
.ContentModuleEditable .ModuleElement table.PropertyListComponent tbody th {
width: 35%;
text-align: left;
vertical-align: top;
padding: 7px 4px 4px 2em;
}
.ContentModuleEditable .ModuleElement table.PropertyListComponent tbody th label {
color: #000000;
}
.ContentModuleEditable .ModuleElement table.PropertyListComponent tbody td {
color: #000000;
vertical-align: middle;
padding: 4px 10px 6px 6px;
}
.ContentModuleEditable .ModuleElement table.PropertyListComponent tbody td select {
margin: 0px 0;
}

/*-- ContentModule .OrderListComponent --*/
.ContentModuleEditable .ModuleElement .OrderListComponent table {
margin: 5px 0 0 0;
border: 1px solid #d1d1d1;
}
